class Solution:
    def findProductsOfElements(self, queries):
        max_needed = max(q[1] for q in queries) + 2
        big = []
        i = 1
        while len(big) <= max_needed:
            x = i
            b = 0
            bits = []
            while x:
                if x & 1:
                    bits.append(1 << b)
                x >>= 1
                b += 1
            big.extend(bits)
            i += 1
        res = []
        for f, t, mod in queries:
            prod = 1
            for v in big[f:t + 1]:
                prod = (prod * v) % mod
            res.append(prod)
        return res

