var findProductsOfElements = function(queries) {
    function countTotalSetBits(n) {
        if (n < 0) return 0n;
        let total = 0n;
        let b = 0n;
        while ((1n << b) <= n) {
            const cycle = 1n << (b + 1n);
            const half = 1n << b;
            const fullCycles = (n + 1n) / cycle;
            total += fullCycles * half;
            const rem = (n + 1n) % cycle;
            total += rem > half ? rem - half : 0n;
            b += 1n;
        }
        return total;
    }
    function countSetAtBit(n, b) {
        if (n < 0) return 0n;
        const cycle = 1n << (b + 1n);
        const half = 1n << b;
        const fullCycles = (n + 1n) / cycle;
        let cnt = fullCycles * half;
        const rem = (n + 1n) % cycle;
        cnt += rem > half ? rem - half : 0n;
        return cnt;
    }
    function sumBitPositions(n) {
        if (n <= 0n) return 0n;
        let total = 0n;
        let b = 0n;
        while ((1n << b) <= n) {
            total += b * countSetAtBit(n, b);
            b += 1n;
        }
        return total;
    }
    function prefixSum(idx) {
        if (idx <= 0n) return 0n;
        let lo = 0n, hi = idx;
        while (lo < hi) {
            const mid = (lo + hi + 1n) / 2n;
            if (countTotalSetBits(mid) <= idx) lo = mid; else hi = mid - 1n;
        }
        const n = lo;
        let total = sumBitPositions(n);
        const r = idx - countTotalSetBits(n);
        if (r > 0n) {
            const m = n + 1n;
            const bits = [];
            let bb = 0n;
            while ((1n << bb) <= m) {
                if (m & (1n << bb)) bits.push(bb);
                bb += 1n;
            }
            let rr = Number(r);
            for (let i = 0; i < rr; i++) total += bits[i];
        }
        return total;
    }
    function powmod(base, exp, mod) {
        base = base % mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }
    const res = [];
    for (const [f, t, mod] of queries) {
        const s2 = prefixSum(BigInt(t) + 1n);
        const s1 = prefixSum(BigInt(f));
        const k = s2 - s1;
        res.push(Number(powmod(2n, k, BigInt(mod))));
    }
    return res;
};
